import React, { useState, useEffect } from "react";
import Sidebar from "../components/sidebar";
import Navbar from "../components/navbar";
import Widgets from "../components/widget";
import Chart from "../components/chart";
import Datatable from "../components/datatable";
import "./Admin.css";

const Admin = () => {
  const [widgetData, setWidgetData] = useState([]);
  const [chartData, setChartData] = useState([]);
  const [tableData, setTableData] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const widgetResponse = await fetch("/api/widgets");
        const chartResponse = await fetch("/api/chartdata");
        const tableResponse = await fetch("/api/tabledata");

        const widgets = await widgetResponse.json();
        const chart = await chartResponse.json();
        const table = await tableResponse.json();

        setWidgetData(widgets);
        setChartData(chart);
        setTableData(table);
      } catch (error) {
        console.error("Error fetching admin data:", error);
      }
    };

    fetchData();
  }, []);

  return (
    <div className="admin">
      <Sidebar />
      <div className="adminContainer">
        <Navbar />
        <div className="widgets">
          {widgetData.map((widget, index) => (
            <Widgets key={index} data={widget} />
          ))}
        </div>
        <div className="charts">
          <Chart data={chartData} title="User Analytics" aspect={2 / 1} />
        </div>
        <div className="datatable">
          <DataTable data={tableData} />
        </div>
      </div>
    </div>
  );
};

export default Admin;
